import React, { useState } from 'react'
import Uikit from 'uikit';
import Project from './Project'
import Detail from './Detail';

const HtmlToReactParser = require('html-to-react').Parser;

export default function Projects({ projects }) {

  const [project, setProject] = useState();
  const [projectDescriptionElement, setProjectDescriptionElement] = useState();

  const showProject = (project) => {
    setProject(project)

    const htmlToReactParser = new HtmlToReactParser();
    setProjectDescriptionElement(htmlToReactParser.parse(project.description));

    Uikit.modal("#modal_project").show();
  }

  return (
    <div>
      <section id="projects">
        <h3 className="heading">أعمالي</h3>
        <div
          className="uk-grid-match uk-child-width-1-3@xl uk-child-width-1-3@m uk-child-width-1-2@s uk-child-width-1-1@xs"
          data-uk-grid>
          {projects.map((project, index) => {
            const { name, short, technologies, description } = project;
            return (
              <Project key={index} name={name} short={short} technologies={technologies} description={description} onPress={() => showProject(project)} />
            )
          })}
        </div>
        {false && <button className="show-more">عرض المزيد</button>}
      </section>


      <div id="modal_project" data-uk-modal>
        <div className="uk-modal-full">
          <div className="uk-modal-content">
            <button className="uk-modal-close-full uk-close-large" type="button" data-uk-close></button>
            <div>
              {
                project && (
                  <Detail name={project.name} images={project.images} description={projectDescriptionElement} technologies={project.technologies} />
                )
              }
            </div>
          </div>
        </div>
      </div>

    </div>
  )
}
