import React, { useState, useEffect } from 'react';
import './App.css';
import { Header, Hero, About, Experience, Projects, Contact, Footer } from './components';


function App() {

  const [about, setAbout] = useState();
  const [projects, setProjects] = useState([]);
  const [jobs, setJobs] = useState([]);
  const [loaded, setLoaded] = useState(false);


  useEffect(() => {

    fetch('data.json')
      .then(response => response.json())
      .then(data => {
        const { about, jobs, projects } = data;

        setAbout(about);
        setJobs(jobs);
        setProjects(projects);
        setLoaded(true);
      });
  }, [])

  if (!loaded) {
    return (
      <div className="loading">
        <h3>جاري التحميل ...</h3>
      </div>
    )
  }

  return (
    <div className="uk-container">
      <Header />
      <Hero />
      <div className="animate__animated animate__fadeIn animate__delay-5s">
        <About description={about.description} technologies={about.technologies} />
        <Experience jobs={jobs} />
        <Projects projects={projects} />
        <Contact />
        <Footer />
      </div>
    </div>
  );
}

export default App;
