import React from 'react'

export default function Slide({ images }) {
  return (
    <div className="uk-text-center uk-position-relative uk-visible-toggle uk-light" data-uk-slider="sets: true; finite: false; autoplay: true">

      <ul className="uk-slider-items uk-child-width-1-1">
        {
          images.map((image, index) => {
            return (
              <li key={index}>
                <img src={image} alt="" />
              </li>
            )
          })
        }
      </ul>

      <a className="uk-position-center-left uk-position-small uk-hidden-hover" href="#" data-uk-slidenav-next data-uk-slider-item="next"></a>
      <a className="uk-position-center-right uk-position-small uk-hidden-hover" href="#" data-uk-slidenav-previous data-uk-slider-item="previous"></a>

      <ul className="uk-slideshow-nav uk-dotnav uk-flex-center uk-margin"></ul>

    </div>
  )
}
