import React from 'react'
const HtmlToReactParser = require('html-to-react').Parser;


export default function About({ description, technologies }) {

  const htmlToReactParser = new HtmlToReactParser();
  const reactElement = htmlToReactParser.parse(description);

  return (
    <section id="about">
      <h3 className="heading">من أنا؟</h3>

      <div data-uk-grid>
        <div className="uk-width-auto@m uk-width-1-1@s uk-text-center">
          <img className="avatar" src="https://avatars.hsoubcdn.com/1bc1ca231938d91fb84d609b9a53cb22" alt="" />
        </div>
        <div className="uk-width-expand@m uk-width-1-1@s">
          {reactElement}
          <p>إليك بعض التقنيات التي أعمل بها مؤخرًا:</p>
        </div>
      </div>

      <div className="skills">
        {
          technologies.map(technology => {
            return (
              <span key={technology}>{technology}</span>
            )
          })
        }
      </div>

    </section>
  )
}
